#include <bits/stdc++.h>
using namespace std;
int main(){
    int n,m,k;
    cin>>n>>m>>k;
    long long a[n+1][m+1],b[k+1][k+1],c[n-k+2][m-k+2]={0};
    for (int i=1;i<=n;i++){
        for (int j=1;j<=m;j++){
            cin>>a[i][j];
        }
    }
    for (int i=1;i<=k;i++){
        for (int j=1;j<=k;j++){
            cin>>b[i][j];
        }
    }
    for (int i=1;i<=n-k+1;i++){
        for (int j=1;j<=m-k+1;j++){
            for (int p=i;p<i+k;p++){
                for (int q=j;q<j+k;q++){
                    c[i][j]+=a[p][q]*b[p-i+1][q-j+1];
                }
            }
        }
    }
    for (int i=1;i<=n-k+1;i++){
        for (int j=1;j<=m-k+1;j++){
            cout<<c[i][j]<<" ";
        }
        cout<<endl;
    }
    return 0;
}
